import{_ as a,o as t,c as s,ag as i}from"./chunks/framework.DXGyWiRo.js";const k=JSON.parse('{"title":"复杂类被阻止","description":"","frontmatter":{},"headers":[],"relativePath":"zh/qa/method-complex.md","filePath":"zh/qa/method-complex.md","lastUpdated":1782689832000}'),o={name:"zh/qa/method-complex.md"};function n(l,e,p,d,h,r){return t(),s("div",null,[...e[0]||(e[0]=[i(`<h1 id="复杂类被阻止" tabindex="-1">复杂类被阻止 <a class="header-anchor" href="#复杂类被阻止" aria-label="Permalink to &quot;复杂类被阻止&quot;">​</a></h1><p>当一个类嵌套很深、存在递归引用，或者字段非常多时，EasyYapi 会在达到安全上限后停止展开字段。剩余字段会被静默丢弃，并在 IDE 日志中写下一行 <code>INFO</code> 级别记录：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Element limit exceeded while parsing &lt;全限定类名&gt;. Processed &lt;n&gt; elements. Stopping field expansion.</span></span></code></pre></div><h2 id="内置上限" tabindex="-1">内置上限 <a class="header-anchor" href="#内置上限" aria-label="Permalink to &quot;内置上限&quot;">​</a></h2><table tabindex="0"><thead><tr><th>配置键</th><th>默认值</th><th>含义</th></tr></thead><tbody><tr><td><code>max.elements</code></td><td><code>512</code></td><td>单次构建操作中允许展开的字段总数。</td></tr><tr><td><code>max.deep</code></td><td><code>8</code></td><td>解析嵌套类型字段时的最大深度。</td></tr></tbody></table><p>两者都可以从任意规则来源（工程、扩展、远程、全局）读取。达到上限时 EasyYapi <strong>不会</strong>抛出异常，只是停止为该响应/请求体继续展开字段。</p><h2 id="解决方案" tabindex="-1">解决方案 <a class="header-anchor" href="#解决方案" aria-label="Permalink to &quot;解决方案&quot;">​</a></h2><h3 id="_1-抬高上限" tabindex="-1">1. 抬高上限 <a class="header-anchor" href="#_1-抬高上限" aria-label="Permalink to &quot;1. 抬高上限&quot;">​</a></h3><p>如果类确实需要更多字段，可以在 <code>.easy.api.config</code> 中抬高上限：</p><div class="language-properties vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">properties</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">max.elements</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=2048</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">max.deep</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=16</span></span></code></pre></div><blockquote><p>设置过高可能让导出变慢甚至 OOM，建议逐步抬升。</p></blockquote><h3 id="_2-忽略不必要的字段" tabindex="-1">2. 忽略不必要的字段 <a class="header-anchor" href="#_2-忽略不必要的字段" aria-label="Permalink to &quot;2. 忽略不必要的字段&quot;">​</a></h3><p>用 <a href="./../settings/rules/field_ignore"><code>field.ignore</code></a> 排除不需要文档化的字段：</p><div class="language-properties vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">properties</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">field.ignore</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=groovy:it.name() == </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;complexField&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> || it.type().name().startsWith(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;com.internal.&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span></code></pre></div><h3 id="_3-把复杂类型转换为简单类型" tabindex="-1">3. 把复杂类型转换为简单类型 <a class="header-anchor" href="#_3-把复杂类型转换为简单类型" aria-label="Permalink to &quot;3. 把复杂类型转换为简单类型&quot;">​</a></h3><p>用 <a href="./../settings/rules/json_rule_convert"><code>json.rule.convert</code></a> 把复杂类型替换为简单类型：</p><div class="language-properties vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">properties</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">json.rule.convert</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=groovy:it.type().name()==</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;com.example.ComplexType&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> =&gt; java.util.Map</span></span></code></pre></div><h3 id="_4-覆盖返回类型" tabindex="-1">4. 覆盖返回类型 <a class="header-anchor" href="#_4-覆盖返回类型" aria-label="Permalink to &quot;4. 覆盖返回类型&quot;">​</a></h3><p>如果方法的声明返回类型是膨胀的根源，用 <a href="./multiple-return-types"><code>method.return</code></a> 覆盖为更简单的类型：</p><div class="language-properties vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">properties</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">method.return</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=groovy:</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;com.example.SimpleResult&lt;&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> + it.returnType().name() + </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;&gt;&quot;</span></span></code></pre></div><blockquote><p>不要与 <code>method.return.main</code> 混淆——后者只决定把 <code>@return</code> 文档注释挂到哪个字段上，并不会改变响应 schema。</p></blockquote>`,21)])])}const u=a(o,[["render",n]]);export{k as __pageData,u as default};
